import 'dart:convert';\nimport 'package:shared_preferences/shared_preferences.dart';\nimport 'api_service.dart';\n\nclass StaffAuthService {\n  final ApiService apiService = ApiService();\n  static const String staffKey = 'staff_user';\n  \n  // Mock staff login (in production, this would be proper authentication)\n  Future<Map<String, dynamic>?> loginStaff(String staffId, String pin) async {\n    try {\n      // For demo purposes, we'll use hardcoded staff credentials\n      final mockStaff = {\n        'staff_001': {\n          'id': 'staff_001',\n          'name': 'Rajesh Kumar',\n          'role': 'Dyeing Specialist',\n          'phone': '9876543210',\n          'skills': ['Dyeing'],\n          'workflowStages': ['dyeing'],\n          'pin': '1234'\n        },\n        'staff_002': {\n          'id': 'staff_002',\n          'name': 'Priya Sharma',\n          'role': 'Master Cutter',\n          'phone': '9876543211',\n          'skills': ['Cutting'],\n          'workflowStages': ['cutting'],\n          'pin': '1234'\n        },\n        'staff_003': {\n          'id': 'staff_003',\n          'name': 'Amit Patel',\n          'role': 'Senior Tailor',\n          'phone': '9876543212',\n          'skills': ['Stitching'],\n          'workflowStages': ['stitching'],\n          'pin': '1234'\n        },\n        'staff_004': {\n          'id': 'staff_004',\n          'name': 'Sneha Desai',\n          'role': 'Khakha Expert',\n          'phone': '9876543213',\n          'skills': ['Khakha'],\n          'workflowStages': ['khakha'],\n          'pin': '1234'\n        },\n        'staff_005': {\n          'id': 'staff_005',\n          'name': 'Vikram Singh',\n          'role': 'Maggam Artist',\n          'phone': '9876543214',\n          'skills': ['Maggam'],\n          'workflowStages': ['maggam'],\n          'pin': '1234'\n        },\n      };\n      \n      final staff = mockStaff[staffId];\n      if (staff != null && staff['pin'] == pin) {\n        // Save staff data\n        final prefs = await SharedPreferences.getInstance();\n        await prefs.setString(_staffKey, jsonEncode(staff));\n        return staff;\n      }\n      \n      return null;\n    } catch (e) {\n      print('Login error: $e');\n      return null;\n    }\n  }\n  \n  // Get current logged-in staff\n  Future<Map<String, dynamic>?> getCurrentStaff() async {\n    try {\n      final prefs = await SharedPreferences.getInstance();\n      final staffJson = prefs.getString(_staffKey);\n      if (staffJson != null) {\n        return jsonDecode(staffJson);\n      }\n      return null;\n    } catch (e) {\n      print('Get current staff error: $e');\n      return null;\n    }\n  }\n  \n  // Logout staff\n  Future<void> logout() async {\n    try {\n      final prefs = await SharedPreferences.getInstance();\n      await prefs.remove(_staffKey);\n    } catch (e) {\n      print('Logout error: $e');\n    }\n  }\n  \n  // Check if staff is logged in\n  Future<bool> isLoggedIn() async {\n    final staff = await getCurrentStaff();\n    return staff != null;\n  }\n}\n